SELECT S.GENERO AS GENERO_PREDOMINANTE FROM ESTAGIO E JOIN SERVIDOR S ON S.PK_SIAPE = E.FK_SIAPE WHERE LOWER(E.CAMPUS) LIKE LOWER('%anapolis%') AND (LOWER(E.CURSO) LIKE LOWER('%ciencia da computa%') OR LOWER(E.CURSO) LIKE LOWER('%ciencia da computa%')) AND (LOWER(E.TIPO) LIKE LOWER('%nao obrigat%') OR LOWER(E.TIPO) LIKE LOWER('%nao obrigat%')) AND E.DATA_INICIO >= (DATE('now', '-5 years')) AND S.GENERO IS NOT NULL GROUP BY S.GENERO ORDER BY COUNT(*) DESC LIMIT 1